export const lpic2_quiz_pool = [
  // Topic 200: Capacity Planning
  { id: 'lpic2-200-1', topicId: 1, question: 'Quale comando fornisce una vista dinamica e in tempo reale del sistema e dei processi in esecuzione, evidenziando le risorse di CPU e memoria?', options: ['free', 'top', 'uptime', 'vmstat'], answer: 1, explanation: 'Il comando `top` fornisce una vista in tempo reale dei processi.' },
  { id: 'lpic2-200-2', topicId: 1, question: 'Quale comando utilizzeresti per visualizzare statistiche di I/O dettagliate per i dispositivi a blocchi?', options: ['vmstat', 'iostat', 'netstat', 'mpstat'], answer: 1, explanation: 'Il comando `iostat` monitora il caricamento dei dispositivi di input/output.' },
  { id: 'lpic2-200-3', topicId: 1, question: 'Vuoi collezionare e visualizzare l\'andamento delle performance di sistema nell\'arco di mesi. Quale set di tool è il più adatto?', options: ['top', 'ss', 'Collectd/MRTG/Cacti', 'tcpdump'], answer: 2, explanation: 'Strumenti come Collectd, MRTG e Cacti raccolgono dati storici per graficarli (es. RRDtool).' },
  { id: 'lpic2-200-4', topicId: 1, question: 'A cosa serve principalmente il tool MRTG?', options: ['Monitorare il traffico di rete e la capacità nel tempo', 'Terminare i processi bloccanti', 'Formattare dischi di rete', 'Fare audit dei log'], answer: 0, explanation: 'MRTG (Multi Router Traffic Grapher) serve storicamente per graphare il carico di rete e le performance.' },
  { id: 'lpic2-200-5', topicId: 1, question: 'Qual è lo scopo del comando `sar`?', options: ['Cercare file su disco', 'System Activity Reporter, per collezionare log sulle risorse', 'Salvare archivi di backup', 'Creare script di shell'], answer: 1, explanation: '`sar` (da sysstat) viene impiegato per raccogliere, riportare o salvare report delle attività hardware.' },

  // Topic 201: Linux Kernel
  { id: 'lpic2-201-1', topicId: 2, question: 'Dove risiedono di default i moduli compilati del kernel all\'interno del filesystem?', options: ['/boot/modules/', '/lib/modules/$(uname -r)/', '/etc/kernel/', '/var/lib/modules/'], answer: 1, explanation: 'I moduli sono posizionati sotto `/lib/modules/` identificati con l\'output di uname -r.' },
  { id: 'lpic2-201-2', topicId: 2, question: 'Quale target della direttiva "make" si usa per creare un\'immagine compressa del kernel (> 2.6)?', options: ['make zImage', 'make bzImage', 'make vmlinux', 'make install'], answer: 1, explanation: '`make bzImage` crea un "big zImage" superando i limiti fisiologici di architettura della vecchia zImage.' },
  { id: 'lpic2-201-3', topicId: 2, question: 'Nella compilazione del kernel da zero, quale comando avvia l\'interfaccia testuale a menu basata su ncurses?', options: ['make config', 'make menuconfig', 'make xconfig', 'make defconfig'], answer: 1, explanation: '`make menuconfig` offre il menu a console classico ncurses.' },
  { id: 'lpic2-201-4', topicId: 2, question: 'Quale comando è preferibile per caricare un modulo a runtime includendo automaticamente le sue dipendenze?', options: ['insmod', 'modinfo', 'modprobe', 'rmmod'], answer: 2, explanation: '`modprobe` usa la mappa di moduli per caricare anche eventuali prerequisiti.' },
  { id: 'lpic2-201-5', topicId: 2, question: 'Quale file funziona da mappa dei simboli per localizzare l\'allocamento in memoria del kernel da debugarlo?', options: ['vmlinux', 'System.map', 'bzImage', 'initrd'], answer: 1, explanation: 'Il file `System.map` contiene la tabella di riferimento dei simboli e relativi indirizzi esadecimali.' },

  // Topic 202: System Startup
  { id: 'lpic2-202-1', topicId: 3, question: 'Sotto il vecchio SysVinit, quale file definisce il runlevel predefinito al boot?', options: ['/etc/inittab', '/etc/runlevel', '/boot/grub/grub.cfg', '/etc/init.d/rcS'], answer: 0, explanation: 'Il record "id:X:initdefault" viene eletto da `/etc/inittab`.' },
  { id: 'lpic2-202-2', topicId: 3, question: 'In distribuzione Debian, quale utility wrap aggiorna il file grub.cfg in base alle nuove configurazioni?', options: ['grub-install', 'grub2-mkconfig', 'update-grub', 'grub-setup'], answer: 2, explanation: 'Debian/Ubuntu forniscono lo script wrap `update-grub`.' },
  { id: 'lpic2-202-3', topicId: 3, question: 'Dovendo eseguire un recovery, quale target di systemd equivale parzialmente alla "single-user mode"?', options: ['runlevel1.target', 'rescue.target', 'single.target', 'emergency.target'], answer: 1, explanation: 'Il `rescue.target` di systemd espone una shell d\'emergenza isolata limitata localmente.' },
  { id: 'lpic2-202-4', topicId: 3, question: 'Qual è il percorso tipico in cui viene archiviato il file di configurazione finale generato per GRUB 2?', options: ['/boot/grub/grub.conf', '/boot/grub2/grub2.cfg', '/boot/grub/grub.cfg', '/etc/grub.cfg'], answer: 2, explanation: 'Di default GRUB 2 scrive i propri menu in `/boot/grub/grub.cfg` (o grub2/ a seconda della distro).' },
  { id: 'lpic2-202-5', topicId: 3, question: 'Come si bypassa il sistema init ufficiale tramite il bootloader per ottenere immediatamente i privilegi di root raw?', options: ['init=/bin/sh', 'single', 'rescue', 'bash'], answer: 0, explanation: 'Fornendo `init=/bin/sh` al kernel la macchina apre direttamente una shell senza eseguire service manager.' },

  // Topic 203: Filesystem and Devices
  { id: 'lpic2-203-1', topicId: 4, question: 'Quale file system basato pesantemente sugli extent è diventato il default nella famiglia Red Hat Enterprise 7 e successivi?', options: ['ext4', 'xfs', 'btrfs', 'zfs'], answer: 1, explanation: 'XFS, ideato storicamente da SGI, è lo standard in RHEL a causa dell\'immensa scalabilità e velocità I/O.' },
  { id: 'lpic2-203-2', topicId: 4, question: 'Qual è il tool di base per controllare e riparare errori correnti in una partizione ext4?', options: ['fsck.ext4', 'e2fsck', 'Entrambi A e B', 'xfs_repair'], answer: 2, explanation: 'Sia `fsck.ext4` che `fsck.ext3` sono generalmente link logici al programma natio `e2fsck`.' },
  { id: 'lpic2-203-3', topicId: 4, question: 'Che direttive troviamo all\'interno del file `/etc/fstab`?', options: ['Le opzioni del bootloader', 'La tabella dei file system statici da montare al boot', 'Le credenziali LDAP', 'Le interfacce di rete fisse'], answer: 1, explanation: '`fstab` elenca tutti i filesystem e relativi point of mount per configurarli automaticamente all\'acensione.' },
  { id: 'lpic2-203-4', topicId: 4, question: 'Con smartctl, come mostri all\'istante lo "stato di salute generale" (PASSED/FAILED)?', options: ['-a', '-H', '-i', '-t short'], answer: 1, explanation: 'Il flag `-H` di smartctl genera rapidamente un esito generale di Health basato sul logging S.M.A.R.T. interno.' },
  { id: 'lpic2-203-5', topicId: 4, question: 'Come si clona l\'intero contenuto del CD-ROM dentro un file ISO?', options: ['tar -cvf image.iso /dev/cdrom', 'dd if=/dev/cdrom of=image.iso', 'mkisofs -o image.iso /dev/cdrom', 'cp /dev/cdrom image.iso'], answer: 1, explanation: 'Il comando `dd` copia blocchi di dati alla perfezione; `if=` significa "input file" ed `of=` "output file".' },

  // Topic 204: Advanced Storage
  { id: 'lpic2-204-1', topicId: 5, question: 'Quale tool viene impiegato per plasmare gestire ed emettere report degli array RAID Software Linux?', options: ['lvm', 'fdisk', 'mdadm', 'parted'], answer: 2, explanation: '`mdadm` sta per "multiple device admin" per unificare i vecchi strumenti in formato software natio.' },
  { id: 'lpic2-204-2', topicId: 5, question: 'Qual è il livello RAID che esegue esclusivamente data mirroring puro, garantendo duplicazione fisica senza striping?', options: ['RAID 0', 'RAID 1', 'RAID 5', 'RAID 10'], answer: 1, explanation: 'Il livello 1 è puramente dedicato al mirror fault-tolerance in scala 1 a 1.' },
  { id: 'lpic2-204-3', topicId: 5, question: 'In Logica LVM, quale comando estende un "Volume Group" con un disco neo inizializzato?', options: ['pvcreate', 'vgextend', 'lvextend', 'vgcreate'], answer: 1, explanation: '`vgextend [nomeGruppo] [device]` accoda fisicamente il nuovo disco all\'interno della cassa virtuale (VG).' },
  { id: 'lpic2-204-4', topicId: 5, question: 'Che parametro usa hdparm per compiere una statistica della velocità di lettura dal magnetico / flash disk aggirando il buffering della pagecache?', options: ['-T', '-S', '-t', '-y'], answer: 2, explanation: 'Il parametro `-t` per "timing buffer-cache reads" indica il raw sequential speed hardware.' },
  { id: 'lpic2-204-5', topicId: 5, question: 'Su cosa si basa un sistema iSCSI?', options: ['Crittografia end-to-end P2P', 'Incapsulare logiche SCSI puro mediante reti TCP/IP comuni', 'Sostituto open-source di SMB e NFS', 'Connettori hardware SAS su rame'], answer: 1, explanation: 'iSCSI emula veri blocchi di storage fisico scambiando comandi SCSI classici sopra i pacchetti IP della LAN.' },

  // Topic 205: Network Configuration
  { id: 'lpic2-205-1', topicId: 6, question: 'Quale alternativa moderna di comando sostituisce `arp -n` per esaminare la tabella dei vicini (cache L2)?', options: ['arp -n', 'ip neigh show', 'netstat -rn', 'route -n'], answer: 1, explanation: '`ip neigh show` esplora la tabella dei nodi adjacenti registrati dalla nuova architettura iproute2.' },
  { id: 'lpic2-205-2', topicId: 6, question: 'Attraverso la suite moderna iproute2, come vedi l\'attuale routing table di tutti i default gateway?', options: ['route', 'ip route show', 'netstat -r', 'ifconfig'], answer: 1, explanation: '`ip r` o `ip route show` visualizza i percorsi definiti.' },
  { id: 'lpic2-205-3', topicId: 6, question: 'Qual è il risultato dell\'opzione `-c 4` nel comando ping?', options: ['Fissa quattro host target', 'Invia quattro pacchetti ECHO_REQUEST e poi conclude', 'Aumenta a 4ms l\'intervallo', 'Fissa una porta specifica.'], answer: 1, explanation: 'Il Count limite (-c 4) ferma l\'iterazione di ping al momento raggiunto della limitazione specificata.' },
  { id: 'lpic2-205-4', topicId: 6, question: 'Qual è lo strumento standard a riga di comando per catturare o eseguire sniffer pacchetti in rete per diagnosi?', options: ['wireshark', 'nmap', 'tcpdump', 'tracepath'], answer: 2, explanation: '`tcpdump` intercetta flussi di pacchetti in ingresso e in uscita.' },
  { id: 'lpic2-205-5', topicId: 6, question: 'Su quale porta standard transita la crittografia HTTPS over SSL/TLS?', options: ['80', '21', '22', '443'], answer: 3, explanation: 'La connessione HTTP Secure si muove di default su porta standard assegnata 443 TCP.' },

  // Topic 206: System Maintenance
  { id: 'lpic2-206-1', topicId: 7, question: 'Qual è l\'ordine corretto e archetipo per compilare dal codice i tgz software C in un Linux vanilla?', options: ['make > make install > ./configure', './configure > make > make install', 'make install > ./configure > make', 'untar > make install > ./configure'], answer: 1, explanation: '1. Creare makefile via ./configure. 2. Compilare eseguibili con make. 3. Spostarli a sistema tramite make install.' },
  { id: 'lpic2-206-2', topicId: 7, question: 'Quale tool trasferisce efficientemente la sincronia dei file, comparando la checksum e inviando i chunk modificati ("delta algorithms")?', options: ['cp', 'scp', 'ftp', 'rsync'], answer: 3, explanation: 'rsync è l\'eccellenza open source per le replicazioni intelligenti e incrementali.' },
  { id: 'lpic2-206-3', topicId: 7, question: 'Cos\'è deputato a fare il comando `strace` su sistema?', options: ['Trovare stringhe nei file binari protetti', 'Tracciare le "system call" API del kernel richieste da un identificato programma', 'Creare lo swap virtuale', 'Testare la Rete'], answer: 1, explanation: '`strace` aggancia PID passati ed elenca tutti gli accessi in I/O intercedendo con le kernel syscalls in real time.' },
  { id: 'lpic2-206-4', topicId: 7, question: 'Quale tool elenca minuziosamente tutti i file in uso momentaneamente dai demoni attivi del sistema?', options: ['lsof', 'ps', 'top', 'find'], answer: 0, explanation: '`lsof` = List Open Files. Fondamentale poichè tutto in Linux è gestito semanticamente come un file o handler socket.' },
  { id: 'lpic2-206-5', topicId: 7, question: 'Nel comando tar standard, quale set di flag decomprime e ripristina all\'aperto un grosso archivio compresso `.tar.gz`?', options: ['-cvf', '-xvf', '-zxvf', '-jcvf'], answer: 2, explanation: 'x estrae, v mostra i log testuali file per file, z un-zippa lo standard gzip ed f specifica il path ad estrarne.' },

  // Topic 207: Domain Name Server
  { id: 'lpic2-207-1', topicId: 8, question: 'Tra i vari record in zona DNS (BIND), quale serve primariamente a tradurre un FQDN direttamente ad una stringa IPv4?', options: ['MX', 'CNAME', 'A', 'AAAA'], answer: 2, explanation: 'A Record (Address). Un eventuale AAAA punterebbe ai blocchi d\'indirizzi protocollo IPv6.' },
  { id: 'lpic2-207-2', topicId: 8, question: 'Prima di ricaricare brutalmente una zona modificata in configurazione BIND, quale test formale ne scongiura stop rovinosi?', options: ['named-checkconf', 'named-checkzone', 'dns-lint', 'dig'], answer: 1, explanation: 'Il tool checkzone simula e parserizza la macro sintattica interna per validarne l\'accensione reale.' },
  { id: 'lpic2-207-3', topicId: 8, question: 'Cosa assicura l\'utilità della designazione di un Record MX?', options: ['Ridirezionali nomi su medesimi alias', 'Designa le preferenze relative al Mail Exchange Server di rotta.', 'Indirizzi statici dei name server autoritativi', 'Dati informazionali liberi (TXT)'], answer: 1, explanation: 'L\'MX accusa gli internet route su quale macchina riversare localmente il flusso di posta via porta 25 o SMTPS.' },
  { id: 'lpic2-207-4', topicId: 8, question: 'Per ovviare al DNS Spoofing, quale struttura dota le estensioni dei domini di firme cifrate e chiavi asimmetriche valide?', options: ['DNS-Over-HTTPS (DoH)', 'TLS', 'DNSSEC', 'TSIG'], answer: 2, explanation: 'Il protocollo esteso DNSSEC incorpora la gerarchia di firma digitale per le traduzioni d\'indirizzo del Web Internazionale.' },
  { id: 'lpic2-207-5', topicId: 8, question: 'Dove incrociamo o modifichiamo di solito il file originario d\'istruzioni per istanziare BIND (named)?', options: ['/etc/bind/bind.conf', '/etc/named.conf', '/var/named/config', '/etc/resolv.conf'], answer: 1, explanation: 'Nella stragrande maggioranza Linux la entry di configurazione per DNS BIND giace in `/etc/named.conf`.' },

  // Topic 208: Web Services
  { id: 'lpic2-208-1', topicId: 9, question: 'Come chiami il blocco direttivo che un Server Apache alloca a più siti, ognuno discriminato in base al nome FQDN?', options: ['<Directory>', '<ServerHost>', '<VirtualHost>', '<Website>'], answer: 2, explanation: 'I blocchi VirtualHost permettono logicamente il mapping portando multi-domini sulla singola socket listener HTTP(s).' },
  { id: 'lpic2-208-2', topicId: 9, question: 'Per cos\'è celebrato in primo piano il web server "Nginx" rispetto ai modelli originari precedenti?', options: ['Server di risoluzione dei nomi integrata pura', 'Celerità d\'Event-Driven ad alto carico su funzioni di Reverse-Proxy / Multi-Balancing', 'Ottimizzazione del server grafico natio locale x11', 'Linguaggio C natio e precompilato dentro il kernel'], answer: 1, explanation: 'Il Load-Balancing su Eventi limitando l\'esplosione dei task e thread su backend dinamici php/python ed espletando Proxy.' },
  { id: 'lpic2-208-3', topicId: 9, question: 'Per natura ed heritage concettuale, cos\'è il daemon "Squid"?', options: ['Relay SMTP', 'Proxy Web ad alte performance per Caching', 'Engine SQL distribuito in clustering', 'Virtual manager di macchine virtuali KVM'], answer: 1, explanation: 'È un Caching web Proxy Proxy, ottimizzato storicamente con ACL a scopo intranet.' },
  { id: 'lpic2-208-4', topicId: 9, question: 'Qual è il Modulo caricato all\'occorrente in Apache per instaurare e servire Tunnel Sicuri su protocollo SSL/TLS (HTTPS)?', options: ['mod_rewrite', 'mod_security', 'mod_ssl', 'mod_proxy'], answer: 2, explanation: 'Il `mod_ssl` offre il collegamento diretto a librerie libssl/openssl applicative per proteggere in cryptos stream HTTP.' },
  { id: 'lpic2-208-5', topicId: 9, question: 'Su che TCP Port è impostato globalmente Squid proxy al suo rilascio vergine primario?', options: ['80', '443', '3128', '8080'], answer: 2, explanation: 'Il default preinstallato ascolta specificatamente ed in attesa sulla port 3128.' },

  // Topic 209: File Sharing
  { id: 'lpic2-209-1', topicId: 10, question: 'Il panorama Linux nativo per condividere o montare volumi direttamente fra un dominio Active Directory Microsoft o Workgroup MS si basa essenzialmente su:', options: ['NFS', 'Samba', 'FTP', 'SSHFS'], answer: 1, explanation: 'Samba ricrea lato GNU e Unix-Like i protocolli di livello utenza Windows come file Server CIFS e NetBIOS interconnesso.' },
  { id: 'lpic2-209-2', topicId: 10, question: 'Il server daemon Samba prende disposizioni primarie ed ACL dai parametri dettati in quale locazione assoluta standard?', options: ['/etc/smb/smb.conf', '/etc/samba/smb.conf', '/usr/local/samba.cfg', '/var/lib/samba/config'], answer: 1, explanation: 'Punto d\'ingresso del Domain / Workgroup in `/etc/samba/smb.conf`.' },
  { id: 'lpic2-209-3', topicId: 10, question: 'Nei Server NFS, la lista vera e propria dove stabiliamo chi vede una share e la mappa utenze è gestita dal file interno?', options: ['/etc/exports', '/etc/nfs.conf', '/etc/fstab', '/etc/samba/smb.conf'], answer: 0, explanation: 'Esempio sintassi `/etc/exports`:   /srv/share   192.168.1.0/24(rw,sync,no_root_squash)' },
  { id: 'lpic2-209-4', topicId: 10, question: 'Per allineare e attivare l\'elenco del demone NFS ricaricandolo senza interrompere attivamente i client on-line quale comando avviamo in root?', options: ['nfs-update', 'systemctl reload nfs', 'exportfs -a / -r', 'mount -a'], answer: 2, explanation: '`exportfs -arv` ordina il parsing e push live delle regole ad-hoc esposte dal file .exports senza ricaricamento systemctl hard code.' },
  { id: 'lpic2-209-5', topicId: 10, question: 'Il manager Samba possiede una directory file password separata dagli Shadow Users classici di un Linux. Se vogliamo aggiungervi l\'utente "Claudio", digitiamo: ', options: ['smbpasswd -a claudio', 'useradd claudio', 'passwd samba claudio', 'pdbedit -n claudio -new'], answer: 0, explanation: 'Aggiunge un nome UNIX regolarmente attivo ad uno con privilegi Samba tramite la utility smbpasswd -a' },

  // Topic 210: Network Client Management
  { id: 'lpic2-210-1', topicId: 11, question: 'Quale Daemon protocollo assegna e gestisce in leasing transitorio un blocco Indirizzi IPv4 ed IPv6 nel network globale per evitare duplicità di client host manuali?', options: ['DNS', 'DHCP', 'ARP', 'ICMP'], answer: 1, explanation: 'Il Dynamic Host Configuration definisce il Pool su scala enterprise in concessione affitto / lease ai computer.' },
  { id: 'lpic2-210-2', topicId: 11, question: 'Nel contesto dei Moduli, perché PAM risulta essere ormai lo Standard unificato di tutto lo spazio utenza locale?', options: ['Raccoglie i pacchetti repo come Aptitude', 'Dona a demoni separati ed app una "scatola nera" pluginica standardizzata e dinamica prettamente per la Gestione Autenticazioni senza ricompilare tool originari.', 'Regola il livello fisico del link router network.', 'Cripta i Kernel log d\'avvio.'], answer: 1, explanation: 'Pluggable Authentication Modules isola il livello codice "sicurezza/cripto-pass/Token e Fingerprint" da quello del semplice Programma che la richiede per accessi.' },
  { id: 'lpic2-210-3', topicId: 11, question: 'Se citi LDAP, storicamente per quale servizio essenziale viene inquadrato su reti promiscue moderne?', options: ['Rintraccio autenticazione utenze (Linux Directory LDAP)', 'Protocollo Directory Leggero d\'Autenticazione condivisa e Gestione Gerarchie Dati centralizzata.', 'Connessione tunnel layer due locale LAN.', 'Interfaccia e framework dati per gestire DataBase enormi Postgre. '], answer: 1, explanation: 'LDAP o Lightweight Directory Access Protocol innalza il dominio gerarchico delle policy / address books / gruppi di sicurezza trasversali ed univoci server.' },
  { id: 'lpic2-210-4', topicId: 11, question: 'All\'interno delle interfacce TAP e TUN fornite nei protocolli OpenVPN in Linux, su quale frame logico OSI s\'interfaccia il modulo device `TUN` in via strettamente preferenziale?', options: ['Fisico Layer Zero e MacAddress bridge.', 'Incapsula il Layer 3, ovvero Indirizzamenti IP crittografati e instradati in routing senza il layer datalink del MAC frame Ethernet.', 'Un file proxy su porta applicativo OSI limitato all\'Header.', 'EsCLUSIVAMENTE lo stacking della VLAN trunk in L2 e MAC filter promiscuos'], answer: 1, explanation: 'I tunnel ip "tun" sono in layer 3 routing OSI.' },
  { id: 'lpic2-210-5', topicId: 11, question: 'A quale protocollo socket e limitazione di Porta è assegnabile il demone base di OpenVPN se rilasciato natio in factory defaults configurazione UDP?', options: ['1194 UDP', '22 TCP', '443 TCP', '53 UDP'], answer: 0, explanation: 'Di design natio ed IANA allocato ufficiale è in 1194 per la trasmissione del client VPN. UDP prediletto alla scalabilità pacchetti.' },

  // Topic 211: E-Mail Services
  { id: 'lpic2-211-1', topicId: 12, question: 'A mezzo di quale Standard IETF i vari server mondiali MTA come Exim, Postfix e Sendmail interscambiano server-to-server il Payload o trasmettono in Relay in entrata le buste dell\'utenza esterna locale?', options: ['POP3', 'IMAP', 'SMTP', 'SNMP'], answer: 2, explanation: 'Simple Mail Transfer Protocol, RFC porta 25-587 o 465 (Secure) garantisce lo Standard Interscambio di busta envelope e Payload d\'intestazione eBody messaggi.' },
  { id: 'lpic2-211-2', topicId: 12, question: 'Al cospetto del celebre MTA Postfix, la colonna portante dei settaggi operazionali di restrizione traffico, domini virtualizzati ecc. dimora di prassi nel file assoluto?', options: ['/etc/postfix/master.cf', '/etc/postfix/main.cf', '/etc/mail/sendmail.cf', '/var/spool/postfix/config'], answer: 1, explanation: 'Il `main.cf` è lo scoglio dominante. Master.cf descrive e manipola istanze daemon d\'ascolto multiple port side ecc.' },
  { id: 'lpic2-211-3', topicId: 12, question: 'Oggi l\'offerta applicativa di Dovecot Server rimpiazzerà o complementerà quasi sempre il software MTA. Cosa permette di fruire alle cassette locali Mbox e Maildir per utenza lato Client / Telefonia in mobilità internet?', options: ['La conversione dei moduli DNS AntiSpam.', 'I servizi dedicati escluisivamente all\'apertura ed esplorazione sincrona delle mailbox protocollando nativamente protocolli IMAP ad alte prestazioni.', 'L\'archiviazione centralizzata Proxy dei messaggi persi per fail over.', 'La pulizia del codice crittografico Header dei protocolli SMTP Postfix.'], answer: 1, explanation: 'Dovecot Server è globalmente lo standard provider d\'Infrastrutture mail-retrieving in Pop3 - IMAP per la Lettura asincrona client / Server.' },
  { id: 'lpic2-211-4', topicId: 12, question: 'Dei vari Delivery Agents storici per Linux (MDA), quale tra Procmail e Sieve ha una forte inclinazione e capacità integrata nel server di consegna finale?', options: ['Affinare l\'instradamento della spedizione mail bloccandola sulle ACL esterne DNS.', 'Filtrare a posteriori in inbox la Posta, e stabilire direttive come deviarla per categorie o applicarci marcature AntiSpam basandosi da espressioni al contenuto o header locali.', 'Creare archivi e Snapshot live del database ldap unito al kernel block.', 'Compilare un registro DNS pubblico e renderlo in ascolto IMAP aperto. '], answer: 1, explanation: 'I vari Procmail o Scripts "Sieve" operano un Filtro intelligente all\'ultimissimo passaggio dell\'imbustatazione nel Mailbox Dir finale, scremando ed instradandone lo smistamento tra Folders utente.' },
  { id: 'lpic2-211-5', topicId: 12, question: 'Trovandoci sul modulo MTA Postfix e avendo ricreato alias nel classico file locale `/etc/aliases`, quale riga di processo rigenererà la Base di mapping binaria (Hash Map)?', options: ['makemap', 'newaliases', 'postmap', 'systemctl reload postfix'], answer: 1, explanation: 'Su derivati Postfix la dicitura storicamente compatibile in Sendmail Style passata al linker `newaliases` edita il binary map (.db).' },

  // Topic 212: System Security
  { id: 'lpic2-212-1', topicId: 13, question: 'Riferendosi al Packet Filtering Legacy base "iptables", quale Table integrata è circoscritta interamente per governare alterazioni NAT pre-routing o manipolare IP Privazioni Natter?', options: ['filter', 'mangle', 'nat', 'raw'], answer: 2, explanation: 'La Tabella logica nominata "nat". Iptables rintraccia ed elabora IP Routing Alterations SNAT / DNAT od in Masquerading interno a questa tab designata d\'isolamento.' },
  { id: 'lpic2-212-2', topicId: 13, question: 'Dei vari Daemon Open Source ausiliari alla sicurezza moderna basati su Pattern Matching Python, quale rianalizzerà i report Log di sistema applicativi al volo ed avvierà Drop ed inibizioni in IP Tables di blocco attacchi ripetitivi e Brute-Force automatici Server esterni passanti come il Ddos su ssh o wordpress?', options: ['Snort / Suricata', 'Fail2ban', 'Nmap', 'OpenVAS/Nessus'], answer: 1, explanation: 'Lo Script Daemon Fail2Ban innalza il muro drop Iptables e Null Route verso l\'aggressore bannato provvisoriamente monitorandone le tracce e reiterazioni.' },
  { id: 'lpic2-212-3', topicId: 13, question: 'Volendo testare come Ethical Hacker il set e Footprint delle versioni attive esposte e vulnerabili di un nostro potenziale Client o Server, il tool caposaldo per Network Mapping di Porte e Servizi?', options: ['tcpdump stream socket debug', 'wireshark analizer LAN', 'nmap portscan & versioning match', 'ping scan sweeping sweep'], answer: 2, explanation: 'L\'NMAP (Network Mapper). Permette a 360 Gradi la ricognizione profonda remota da terminale della Mappa Porte Esistenti a Livello Host o intera SubNet aziendale e test.' },
  { id: 'lpic2-212-4', topicId: 13, question: 'Riferendoti a Piattaforme strutturate, che Cos\'è storicamente il set di Security Audit "OpenVAS"?', options: ['Una Shell per generare Firewall', 'Strumentazione Server ad-hoc open source finalizzata alla scoperta di falle generiche con un imponente database di Common Vulnerabilities aggiornabile (Vulnerabilty Manager). ', 'Un Server crittografico VPN parallelo OpenVpn', 'Motore applicabile a Desktop ad antivirus in Kernel natio Linux ed Unix.'], answer: 1, explanation: 'OpenVas forkoa dalle versioni iniziali di Nessus Scanner. Si prodiga di eseguire migliaia di Audit simultanei d\'iniezioni su apparati per testarne le gravità critiche e trarne report informativi su Patch Correttive.' },
  { id: 'lpic2-212-5', topicId: 13, question: 'Specificatamente nel filtro rules base preistorico di iptables.. Quale costrutto cambia in positivo da "Accetta incondizionatamente tutto il network passante in INPUT in default policy" al "Scarta ed eclissa ogni cosa silenziando la macchina" ?', options: ['iptables -A INPUT -j DROP', 'iptables -P INPUT DROP', 'iptables -I INPUT DROP', 'iptables -D INPUT DROP'], answer: 1, explanation: 'L\'Argomento Policy "-P". Ristabilisce logicamente d\'Ufficio che la Base Linea comportamentale Firewall sia di base di DROP ed impone quindi di compilare eccezioni esplicite per aprire fessure applicative ed ingressi di Trust (Port forarding). ' },
  // --- NUOVO BATCH 1 (Argomenti 200-204) ---
  { id: 'lpic2-200-6', topicId: 1, question: 'Nell\'output di `vmstat`, cosa indica la colonna `wa`?', options: ['Attesa per la CPU', 'Attesa per l\'I/O', 'Attesa per la rete', 'Attesa per l\'allocazione di memoria'], answer: 1, explanation: 'La colonna `wa` in `vmstat` mostra la percentuale di tempo CPU speso in attesa del completamento delle operazioni di I/O.' },
  { id: 'lpic2-200-7', topicId: 1, question: 'Quale comando fornisce un rapido riepilogo delle medie di carico del sistema (load averages) per gli ultimi 1, 5 e 15 minuti?', options: ['w', 'uptime', 'Entrambi A e B', 'sar'], answer: 2, explanation: 'Sia il comando `w` che `uptime` visualizzano le medie di carico del sistema.' },
  { id: 'lpic2-200-8', topicId: 1, question: 'Qual è il protocollo primario utilizzato da MRTG per raccogliere dati dai dispositivi di rete?', options: ['SSH', 'SMTP', 'SNMP', 'HTTP'], answer: 2, explanation: 'MRTG (Multi Router Traffic Grapher) si affida prevalentemente a SNMP (Simple Network Management Protocol) per raccogliere metriche.' },
  { id: 'lpic2-200-9', topicId: 1, question: 'Quale comando mostra le statistiche delle interfacce di rete, inclusi pacchetti scartati ed errori di overrun?', options: ['netstat -i', 'netstat -r', 'netstat -tulnp', 'ifconfig -a'], answer: 0, explanation: '`netstat -i` visualizza una tabella di tutte le interfacce di rete e le rispettive statistiche di trasmissione/ricezione.' },
  { id: 'lpic2-200-10', topicId: 1, question: 'Quale valore di memoria nell\'output del comando `free` è più indicativo della memoria disponibile per avviare nuove applicazioni senza ricorrere allo swap?', options: ['total', 'used', 'shared', 'available'], answer: 3, explanation: 'La colonna `available` stima quanta memoria è disponibile per avviare nuove applicazioni senza swap fisico.' },
  { id: 'lpic2-200-11', topicId: 1, question: 'Come si configura Collectd per memorizzare le metriche in modo efficiente nel tempo?', options: ['Scrittura su CSV', 'Scrittura tramite RRDtool', 'Scrittura solo su MySQL', 'Scrittura su syslog'], answer: 1, explanation: 'Collectd utilizza spesso il plugin RRDtool (Round Robin Database) per memorizzare i dati delle serie temporali in modo efficiente.' },
  { id: 'lpic2-200-12', topicId: 1, question: 'Quale strumento è costruito specificamente per mostrare l\'utilizzo dell\'I/O per processo in tempo reale, in modo simile a `top`?', options: ['iotop', 'iostat', 'ioping', 'blktrace'], answer: 0, explanation: '`iotop` visualizza un\'interfaccia simile a top che mostra la larghezza di banda di lettura e scrittura I/O per processo.' },
  { id: 'lpic2-200-13', topicId: 1, question: 'Cosa suggerisce fortemente un valore elevato di `si` e `so` in `vmstat`?', options: ['Congestione di rete', 'Collo di bottiglia della CPU', 'Carenza di memoria e swap intenso', 'Guasto hardware del disco'], answer: 2, explanation: 'Elevati tassi di Swap In (`si`) e Swap Out (`so`) indicano che il sistema sta utilizzando intensamente la memoria su disco a causa dell\'esaurimento della RAM.' },
  { id: 'lpic2-200-14', topicId: 1, question: 'Quale comando elenca tutti i socket TCP e UDP in ascolto insieme al PID del processo?', options: ['ss -tulnp', 'netstat -rn', 'ip route', 'arp -a'], answer: 0, explanation: '`ss -tulnp` (o netstat -tulnp) elenca le porte TCP/UDP in ascolto e i relativi ID di processo.' },
  { id: 'lpic2-200-15', topicId: 1, question: 'Nella pianificazione della capacità, cos\'è una "baseline"?', options: ['La capacità massima del server', 'La RAM minima richiesta per il boot', 'Dati storici che rappresentano il normale comportamento del sistema', 'Il limite fisico della scheda di rete'], answer: 2, explanation: 'Una baseline (linea di base) è uno stato noto e normale del sistema registrato nel tempo per confrontarlo con anomalie o crescita futura.' },

  { id: 'lpic2-201-6', topicId: 2, question: 'Quale comando pulisce completamente l\'albero dei sorgenti del kernel, rimuovendo tutti i file compilati e il file .config?', options: ['make clean', 'make mrproper', 'make distclean', 'make wipe'], answer: 1, explanation: '`make mrproper` rimuove tutti i file generati, inclusi `.config` e vari file di backup, garantendo un albero dei sorgenti pulito.' },
  { id: 'lpic2-201-7', topicId: 2, question: 'Qual è lo scopo del comando `depmod`?', options: ['Rimuovere un modulo', 'Generare il file modules.dep per modprobe', 'Visualizzare i dettagli dei moduli', 'Compilare i moduli'], answer: 1, explanation: '`depmod` analizza i moduli del kernel e genera un elenco di dipendenze (`modules.dep`) utilizzato da `modprobe`.' },
  { id: 'lpic2-201-8', topicId: 2, question: 'Quale strumento ricostruisce dinamicamente i moduli del kernel per i driver di terze parti (come Nvidia) al momento dell\'installazione di un nuovo kernel?', options: ['depmod', 'dracut', 'DKMS', 'kmod'], answer: 2, explanation: 'DKMS (Dynamic Kernel Module Support) è un framework che ricompila i moduli esterni del kernel ogni volta che ne viene installato uno nuovo.' },
  { id: 'lpic2-201-9', topicId: 2, question: 'Come puoi visualizzare la configurazione attualmente attiva del kernel in esecuzione (se supportato dal kernel)?', options: ['cat /proc/kcore', 'zcat /proc/config.gz', 'cat /sys/kernel/config', 'dmesg | grep config'], answer: 1, explanation: 'Se l\'opzione `IKCONFIG_PROC` è abilitata, la configurazione del kernel in esecuzione è esposta in `/proc/config.gz`.' },
  { id: 'lpic2-201-10', topicId: 2, question: 'Quale comando elenca tutti i moduli del kernel attualmente caricati?', options: ['lsmod', 'modinfo', 'modprobe -l', 'infomod'], answer: 0, explanation: '`lsmod` formatta il contenuto di `/proc/modules` per mostrare quali moduli del kernel sono attualmente caricati in memoria.' },
  { id: 'lpic2-201-11', topicId: 2, question: 'Qual è la differenza principale tra `initrd` e `initramfs`?', options: ['initrd è un archivio cpio; initramfs è un\'immagine di un dispositivo a blocchi', 'initramfs è un archivio cpio estratto in un tmpfs; initrd è un\'immagine di un dispositivo a blocchi', 'initrd è solo per UEFI', 'initramfs non può caricare moduli'], answer: 1, explanation: '`initramfs` è un approccio moderno e più semplice che utilizza un archivio cpio compresso caricato in un tmpfs, evitando i driver dei dispositivi a blocchi all\'inizio del boot.' },
  { id: 'lpic2-201-12', topicId: 2, question: 'Quale comando visualizza informazioni su un modulo del kernel, come l\'autore, la descrizione e i parametri accettati?', options: ['lsmod', 'modprobe -d', 'modinfo', 'insmod -i'], answer: 2, explanation: '`modinfo` estrae e stampa le informazioni dal file oggetto del modulo stesso.' },
  { id: 'lpic2-201-13', topicId: 2, question: 'Quale comando legge `sysctl.conf` e applica immediatamente i parametri del kernel?', options: ['sysctl -w', 'sysctl -a', 'sysctl -p', 'sysctl -r'], answer: 2, explanation: '`sysctl -p` carica i parametri di configurazione da `/etc/sysctl.conf` (o dal file specificato) nel kernel attivo.' },
  { id: 'lpic2-201-14', topicId: 2, question: 'Dove cerca `udev` le sue regole personalizzate per gli eventi hardware?', options: ['/etc/udev/rules.d/', '/lib/udev/rules.d/', 'Entrambi A e B', '/var/run/udev/'], answer: 2, explanation: '`udev` legge le regole predefinite da `/lib/udev/rules.d/` e le regole personalizzate dell\'amministratore da `/etc/udev/rules.d/`.' },
  { id: 'lpic2-201-15', topicId: 2, question: 'Quale comando rimuove un modulo dal kernel in esecuzione se non è più in uso?', options: ['rmmod', 'insmod -r', 'modprobe -r', 'Entrambi A e C'], answer: 3, explanation: 'Sia `rmmod` che `modprobe -r` possono essere usati per rimuovere moduli, sebbene `modprobe -r` rimuova pulitamente anche le dipendenze non utilizzate.' },

  { id: 'lpic2-202-6', topicId: 3, question: 'In systemd, quale comando imposta il target predefinito su Grafico (equivalente al runlevel 5)?', options: ['systemctl set-default graphical.target', 'systemctl isolate graphical.target', 'systemctl default graphical.target', 'ln -s /lib/systemd/system/graphical.target /etc/inittab'], answer: 0, explanation: '`systemctl set-default` cambia il target di boot predefinito aggiornando il symlink `/etc/systemd/system/default.target`.' },
  { id: 'lpic2-202-7', topicId: 3, question: 'Durante l\'avvio di GRUB 2, quale tasto consente tipicamente di accedere al menu di boot per modificare i parametri del kernel se è nascosto?', options: ['F8', 'F12', 'Shift o Esc', 'Invio'], answer: 2, explanation: 'Tenere premuto `Shift` (per BIOS) o premere `Esc` (per UEFI) interrompe l\'avvio di GRUB 2 e mostra il menu.' },
  { id: 'lpic2-202-8', topicId: 3, question: 'Cosa fa il comando `systemctl isolate`?', options: ['Riavvia il sistema', 'Cambia lo stato operativo corrente in un nuovo target, arrestando i servizi non necessari', 'Disabilita le interfacce di rete', 'Esegue un chroot in un altro ambiente'], answer: 1, explanation: '`isolate` commuta immediatamente il sistema in un nuovo target (come il cambio di runlevel in SysV).' },
  { id: 'lpic2-202-9', topicId: 3, question: 'Quale file contiene le impostazioni globali (come timeout e voce predefinita) utilizzate da grub-mkconfig per generare la configurazione di GRUB 2?', options: ['/etc/grub.d/00_header', '/boot/grub/grub.cfg', '/etc/default/grub', '/boot/grub/menu.lst'], answer: 2, explanation: '`/etc/default/grub` contiene variabili come `GRUB_TIMEOUT` e `GRUB_CMDLINE_LINUX` che dettano la generazione del file finale.' },
  { id: 'lpic2-202-10', topicId: 3, question: 'Cos\'è PXE?', options: ['Un formato di tabella delle partizioni', 'Un metodo per avviare un sistema operativo via rete usando DHCP e TFTP', 'Un bootloader Linux per ARM', 'Un tipo di unità systemd'], answer: 1, explanation: 'Preboot eXecution Environment (PXE) consente alle schede di rete di recuperare un bootloader e un kernel da un server di rete.' },
  { id: 'lpic2-202-11', topicId: 3, question: 'Quale directory contiene gli script modulari eseguiti da `grub-mkconfig`?', options: ['/etc/default/grub', '/etc/grub.d/', '/boot/grub/scripts/', '/lib/grub/'], answer: 1, explanation: 'La directory `/etc/grub.d/` contiene script eseguibili (come 10_linux) che analizzano il sistema durante la generazione di grub.cfg.' },
  { id: 'lpic2-202-12', topicId: 3, question: 'Cos\'è `systemd-boot`?', options: ['Un wrapper SysVinit', 'Un boot manager UEFI leggero', 'Un plugin di GRUB', 'Un tema Plymouth'], answer: 1, explanation: '`systemd-boot` (precedentemente gummiboot) è un semplice boot manager UEFI incorporato in systemd.' },
  { id: 'lpic2-202-13', topicId: 3, question: 'Se perdi la password di root, quale parametro del kernel puoi passare in GRUB per bypassare l\'autenticazione?', options: ['root=/dev/null', 'init=/bin/bash', 'skip_auth=1', 'runlevel=0'], answer: 1, explanation: 'L\'aggiunta di `init=/bin/bash` (o /bin/sh) monta root e avvia immediatamente una shell di root senza chiedere la password.' },
  { id: 'lpic2-202-14', topicId: 3, question: 'Quale comando genera un ramdisk iniziale (initramfs) sui sistemi Red Hat / CentOS?', options: ['mkinitcpio', 'mkinitrd / dracut', 'update-initramfs', 'initramfs-build'], answer: 1, explanation: 'I sistemi basati su RHEL storicamente usavano `mkinitrd` e ora usano nativamente `dracut` per costruire l\'initramfs.' },
  { id: 'lpic2-202-15', topicId: 3, question: 'In SysVinit, quale script è tipicamente responsabile dell\'esecuzione degli script rc per il runlevel definito?', options: ['/etc/rc.local', '/etc/init.d/rc', '/sbin/runlevel', '/bin/sh'], answer: 1, explanation: 'Lo script `/etc/init.d/rc` viene invocato da init con il runlevel come argomento per avviare/arrestare i servizi appropriati in `/etc/rcX.d/`.' },

  { id: 'lpic2-203-6', topicId: 4, question: 'Quale comando visualizza la geometria hardware e le partizioni di un disco?', options: ['df -h', 'lsblk', 'fdisk -l', 'Entrambi B e C'], answer: 3, explanation: 'Sia `lsblk` che `fdisk -l` descrivono i dispositivi a blocchi e le partizioni (fdisk mostra i dettagli della geometria).' },
  { id: 'lpic2-203-7', topicId: 4, question: 'Quale comando converte un filesystem ext3 in ext4 senza perdita di dati?', options: ['tune2fs -O extents,uninit_bg,dir_index /dev/sda1', 'mkfs.ext4 /dev/sda1', 'fsck.ext4 -y /dev/sda1', 'parted /dev/sda1 convert ext4'], answer: 0, explanation: '`tune2fs` consente di attivare funzionalità del filesystem su un disco esistente; l\'aggiunta delle feature ext4 lo converte.' },
  { id: 'lpic2-203-8', topicId: 4, question: 'Quale strumento modifica l\'UUID di un filesystem ext2/ext3/ext4?', options: ['uuidgen', 'blkid', 'tune2fs -U', 'xfs_admin'], answer: 2, explanation: '`tune2fs -U [UUID|random] /dev/sdX` cambia l\'UUID del filesystem sui sistemi ext.' },
  { id: 'lpic2-203-9', topicId: 4, question: 'Quale opzione in `/etc/fstab` monta il filesystem in sola lettura?', options: ['rw', 'ro', 'noexec', 'nosuid'], answer: 1, explanation: 'L\'opzione `ro` specifica il mount in Read-Only (sola lettura).' },
  { id: 'lpic2-203-10', topicId: 4, question: 'Quale comando fornisce informazioni sullo stato e la frammentazione di un filesystem XFS?', options: ['xfs_repair', 'xfs_info', 'xfs_db', 'Nessuno dei precedenti'], answer: 1, explanation: '`xfs_info` stampa i dettagli della geometria e del layout di un filesystem XFS montato.' },
  { id: 'lpic2-203-11', topicId: 4, question: 'Come puoi cancellare in modo sicuro un disco rigido (/dev/sdb) sovrascrivendolo con dati casuali?', options: ['dd if=/dev/urandom of=/dev/sdb bs=1M', 'rm -rf /dev/sdb', 'mkfs.ext4 /dev/sdb', 'fdisk -w /dev/sdb'], answer: 0, explanation: '`dd` leggendo da `/dev/urandom` sovrascrive fisicamente il disco di destinazione con dati binari imprevedibili.' },
  { id: 'lpic2-203-12', topicId: 4, question: 'Cosa fa il comando `badblocks`?', options: ['Formatta il disco', 'Scansiona un dispositivo alla ricerca di settori fisicamente danneggiati', 'Ripara il registro del filesystem', 'Identifica la RAM difettosa'], answer: 1, explanation: '`badblocks` esegue test di lettura/scrittura sui settori per identificare i blocchi fisicamente inutilizzabili su un dispositivo di archiviazione.' },
  { id: 'lpic2-203-13', topicId: 4, question: 'Quale comando Btrfs crea uno snapshot in lettura-scrittura di un subvolume?', options: ['btrfs subvolume snapshot', 'btrfs snap create', 'lvcreate -s', 'btrfs-image'], answer: 0, explanation: '`btrfs subvolume snapshot <sorgente> <destinazione>` crea uno snapshot Copy-on-Write.' },
  { id: 'lpic2-203-14', topicId: 4, question: 'Cos\'è `autofs`?', options: ['Uno strumento per formattare dischi', 'Un daemon che monta automaticamente i filesystem su richiesta', 'Un sostituto di GRUB', 'Un router di pacchetti di rete'], answer: 1, explanation: '`autofs` fornisce il montaggio automatico (montaggio solo quando un utente accede a una directory specifica) e lo smontaggio automatico.' },
  { id: 'lpic2-203-15', topicId: 4, question: 'Quale comando di authoring di supporti ottici crea un\'immagine del filesystem ISO9660?', options: ['cdrecord', 'mkisofs', 'growisofs', 'wodim'], answer: 1, explanation: '`mkisofs` (o genisoimage) prende un albero di directory e genera un file di layout ISO9660 adatto alla masterizzazione.' },

  { id: 'lpic2-204-6', topicId: 5, question: 'In LVM, come si riduce in sicurezza la dimensione di un volume logico?', options: ['lvresize -L -10G /dev/vg/lv', 'Dimensionare prima il filesystem interno al LV, poi ridimensionare il LV', 'Ridimensionare prima il LV, poi ridimensionare il filesystem', 'Non è possibile ridurre un LV'], answer: 1, explanation: 'È necessario rimpicciolire il filesystem (es. resize2fs) PRIMA di rimpicciolire il LV per evitare di corrompere i confini dei dati.' },
  { id: 'lpic2-204-7', topicId: 5, question: 'Quando si gestisce un array software RAID 5 con `mdadm`, cosa succede se un disco si guasta?', options: ['I dati vengono persi permanentemente', 'L\'array opera in modalità degradata usando la parità per calcolare i dati mancanti', 'Il sistema va immediatamente in kernel panic', 'L\'array passa a RAID 0'], answer: 1, explanation: 'RAID 5 può tollerare esattamente un guasto al disco, operando in "modalità degradata" fino alla ricostruzione.' },
  { id: 'lpic2-204-8', topicId: 5, question: 'Quale comando avvia una sessione iSCSI per scoprire i target su un server?', options: ['iscsiadm -m discovery -t sendtargets -p <IP>', 'iscsid --scan', 'mount -t iscsi', 'lvscan'], answer: 0, explanation: '`iscsiadm` è lo strumento CLI per interagire con l\'iniziatore open-iscsi per scoprire e autenticarsi nei target.' },
  { id: 'lpic2-204-9', topicId: 5, question: 'Cosa mostra il comando LVM `vgdisplay`?', options: ['Solo i volumi fisici', 'Solo i volumi logici', 'Attributi dei Gruppi di Volumi come dimensione totale, PE liberi e PE allocati', 'Gli UUID dei file system'], answer: 2, explanation: '`vgdisplay` mostra i metadati relativi ai Volume Groups, inclusi i dettagli sulla capacità dei Physical Extent (PE).' },
  { id: 'lpic2-204-10', topicId: 5, question: 'Come si aggiunge un disco di riserva (spare) a un array RAID `mdadm` esistente (/dev/md0)?', options: ['mdadm --add /dev/md0 /dev/sdX', 'mdadm --grow /dev/md0 --size=spare', 'mdadm --create /dev/md0 /dev/sdX', 'Non è possibile aggiungere spare ad array attivi'], answer: 0, explanation: 'Il flag `--add` (o `-a`) aggiunge a caldo un dispositivo di riserva a un array esistente.' },
  { id: 'lpic2-204-11', topicId: 5, question: 'Qual è lo scopo degli snapshot LVM?', options: ['Creare backup permanenti su nastro', 'Catturare istantaneamente lo stato di un Volume Logico (Copy-on-Write) per backup coerenti', 'Accelerare le letture del disco', 'Convertire ext4 in xfs'], answer: 1, explanation: 'Gli snapshot tracciano le modifiche tramite CoW, consentendo di eseguire il backup di uno stato congelato nel tempo di un volume senza tempi di inattività.' },
  { id: 'lpic2-204-12', topicId: 5, question: 'In un ambiente iSCSI, cos\'è un IQN?', options: ['Internal Query Network', 'iSCSI Qualified Name', 'Internet Quota Node', 'Initial Queue Number'], answer: 1, explanation: 'L\'iSCSI Qualified Name (IQN) è un identificatore univoco globale per gli iniziatori e i target iSCSI.' },
  { id: 'lpic2-204-13', topicId: 5, question: 'Quale flag di `hdparm` ottiene/imposta il tempo di spindown per un disco?', options: ['-S', '-y', '-Z', '-B'], answer: 0, explanation: '`hdparm -S` imposta il timeout di standby (spindown) per un disco IDE/SATA/SAS.' },
  { id: 'lpic2-204-14', topicId: 5, question: 'Quale file memorizza dinamicamente lo stato e i dettagli degli array RAID software `mdadm`?', options: ['/etc/mdadm.conf', '/proc/mdstat', '/var/log/raid.log', '/sys/block/raid'], answer: 1, explanation: '`/proc/mdstat` fornisce un riepilogo in tempo reale degli array RAID software del kernel e del loro stato di sincronizzazione.' },
  { id: 'lpic2-204-15', topicId: 5, question: 'Quale componente LVM viene creato direttamente su una partizione del disco grezzo?', options: ['Logical Volume (LV)', 'Volume Group (VG)', 'Physical Volume (PV)', 'Volume Extent (VE)'], answer: 2, explanation: 'Un Physical Volume (PV) è la struttura LVM di base creata direttamente su un disco o una partizione.' },

  // --- NUOVO BATCH 2 (Argomenti 205-208) ---
  { id: 'lpic2-205-6', topicId: 6, question: 'Quale comando `ip` assegna l\'indirizzo IPv4 192.168.1.10/24 all\'interfaccia eth0?', options: ['ip address add 192.168.1.10/24 dev eth0', 'ip addr set eth0 192.168.1.10/24', 'ip assign eth0 192.168.1.10/24', 'ifconfig eth0 add 192.168.1.10/24'], answer: 0, explanation: '`ip address add <indirizzo> dev <interfaccia>` è la sintassi corretta.' },
  { id: 'lpic2-205-7', topicId: 6, question: 'Qual è lo scopo del file `/etc/iproute2/rt_tables`?', options: ['Memorizza la cache ARP del sistema', 'Mappa gli ID delle tabelle di instradamento in nomi leggibili dall\'uomo', 'Configura le regole del firewall per iproute2', 'Assegna indirizzi IP statici'], answer: 1, explanation: 'Questo file consente agli amministratori di utilizzare nomi simbolici invece di identificatori numerici per le tabelle di routing.' },
  { id: 'lpic2-205-8', topicId: 6, question: 'Quale strumento viene utilizzato principalmente per configurare i parametri (come SSID o frequenza) di un\'interfaccia di rete wireless in Linux?', options: ['ifconfig', 'iwconfig', 'wpa_supplicant', 'nmcli'], answer: 1, explanation: '`iwconfig` è uno strumento CLI dedicato alla configurazione delle estensioni wireless e delle interfacce di rete wireless.' },
  { id: 'lpic2-205-9', topicId: 6, question: 'Durante il test di una connessione, come si istruisce `ping` a originare specificamente i suoi pacchetti dall\'interfaccia `eth1`?', options: ['ping -S eth1', 'ping -I eth1', 'ping -e eth1', 'ping -i eth1'], answer: 1, explanation: 'Il flag `-I` lega esplicitamente il socket di ping a un\'interfaccia specifica o a un indirizzo IP sorgente.' },
  { id: 'lpic2-205-10', topicId: 6, question: 'Quale comando imposta un gateway predefinito di 10.0.0.1 utilizzando la suite iproute2?', options: ['ip route add default via 10.0.0.1', 'route add default gw 10.0.0.1', 'ip route default 10.0.0.1', 'ip gw set 10.0.0.1'], answer: 0, explanation: '`ip route add default via <IP>` aggiunge una regola di instradamento per il gateway predefinito.' },
  { id: 'lpic2-205-11', topicId: 6, question: 'Come puoi catturare i pacchetti di rete con `tcpdump` e salvarli in un file chiamato `capture.pcap` per una successiva analisi in Wireshark?', options: ['tcpdump > capture.pcap', 'tcpdump -f capture.pcap', 'tcpdump -w capture.pcap', 'tcpdump -o capture.pcap'], answer: 2, explanation: 'Il flag `-w` istruisce tcpdump a scrivere i pacchetti grezzi in un file PCAP specificato.' },
  { id: 'lpic2-205-12', topicId: 6, question: 'Quale strumento Linux è spesso definito il "coltellino svizzero" del networking e può essere utilizzato per la scansione delle porte, il trasferimento di file e la cattura di banner?', options: ['nmap', 'nc (netcat)', 'telnet', 'curl'], answer: 1, explanation: 'Netcat (`nc`) è un\'utility versatile utilizzata per leggere e scrivere su connessioni di rete tramite TCP o UDP.' },
  { id: 'lpic2-205-13', topicId: 6, question: 'Qual è l\'indirizzo di loopback IPv6 equivalente a 127.0.0.1?', options: ['::1', 'fe80::1', '0:0:0:0:0:0:0:1', 'Entrambi A e C'], answer: 3, explanation: '`::1` è il formato abbreviato di `0:0:0:0:0:0:0:1`, che è l\'indirizzo localhost IPv6.' },
  { id: 'lpic2-205-14', topicId: 6, question: 'Quale opzione dell\'utility `ss` visualizza tutti i socket in ascolto *e* quelli stabiliti (non in ascolto)?', options: ['ss -l', 'ss -a', 'ss -t', 'ss -u'], answer: 1, explanation: '`ss -a` (all) stampa sia i socket in ascolto che quelli non in ascolto.' },
  { id: 'lpic2-205-15', topicId: 6, question: 'Per impostazione predefinita, che tipo di pacchetto invia il tradizionale comando Linux `traceroute` per sondare il percorso?', options: ['TCP SYN', 'ICMP Echo Request', 'Datagrammi UDP', 'Query IGMP'], answer: 2, explanation: 'A differenza del `tracert` di Windows che usa ICMP, il `traceroute` standard di Linux sfrutta datagrammi UDP indirizzati a porte elevate con numeri incrementali.' },

  { id: 'lpic2-206-6', topicId: 7, question: 'Quale utility può sostituire `make install` per creare un pacchetto Slackware, RPM o Debian dal sorgente compilato per una rimozione più semplice in seguito?', options: ['autotools', 'checkinstall', 'dpkg-buildpackage', 'rpmbuild'], answer: 1, explanation: '`checkinstall` traccia i file installati da `make install` e crea un pacchetto (come .deb o .rpm) per una gestione pulita dei pacchetti.' },
  { id: 'lpic2-206-7', topicId: 7, question: 'Quale strumento traccia le chiamate alle librerie dinamiche effettuate da un eseguibile (contrariamente alle chiamate di sistema)?', options: ['strace', 'ltrace', 'ldd', 'objdump'], answer: 1, explanation: '`ltrace` intercetta e registra le chiamate alle librerie dinamiche legate a un eseguibile durante l\'esecuzione.' },
  { id: 'lpic2-206-8', topicId: 7, question: 'Quando si estrae un tarball compresso usando `bzip2`, quale flag tipico viene passato a `tar`?', options: ['-z', '-J', '-j', '-b'], answer: 2, explanation: 'Il flag `-j` istruisce GNU tar a decomprimere usando bzip2.' },
  { id: 'lpic2-206-9', topicId: 7, question: 'Quale comando controlla le operazioni delle unità a nastro magnetico come il riavvolgimento e l\'espulsione?', options: ['tape', 'mt', 'tar', 'cpio'], answer: 1, explanation: '`mt` (magnetic tape) è l\'utility standard invocata per controllare i meccanismi fisici delle unità a nastro.' },
  { id: 'lpic2-206-10', topicId: 7, question: 'In `rsync`, cosa fa il flag `-a` (archive)?', options: ['Comprime i dati', 'Sincronizza ricorsivamente e preserva permessi, tempi, proprietà e symlink', 'Elimina i file estranei dalla destinazione', 'Copia solo i file nascosti'], answer: 1, explanation: 'La modalità archivio (`-a`) equivale a `-rlptgoD`, rendendola ideale per eseguire la sincronizzazione identica delle directory.' },
  { id: 'lpic2-206-11', topicId: 7, question: 'Quale comando systemd segnala a un daemon di rileggere semplicemente i suoi file di configurazione senza perdere le connessioni attive?', options: ['systemctl restart', 'systemctl reload', 'systemctl force-reload', 'systemctl refresh'], answer: 1, explanation: '`reload` istruisce in modo sicuro un servizio a rianalizzare le sue configurazioni senza un\'interruzione brutale.' },
  { id: 'lpic2-206-12', topicId: 7, question: 'Qual è la struttura di directory standard su un file system Linux designata specificamente per contenere la maggior parte dei log di servizio generici?', options: ['/usr/log/', '/var/spool/log/', '/var/log/', '/etc/logs/'], answer: 2, explanation: 'La directory `/var/log/` è lo standard conforme a FHS per l\'output dei log di sistema e delle applicazioni.' },
  { id: 'lpic2-206-13', topicId: 7, question: 'Come si può collegare `strace` a un processo daemon già in esecuzione?', options: ['strace -a <PID>', 'strace -p <PID>', 'strace --attach <PID>', 'strace <PID>'], answer: 1, explanation: 'Il flag `-p` costringe strace ad agganciarsi dinamicamente all\'ID di processo specificato.' },
  { id: 'lpic2-206-14', topicId: 7, question: 'Quando si crea un backup esatto bit per bit di una partizione del disco con `dd`, quale parametro definisce la dimensione dei blocchi letti/scritti per migliorare drasticamente la velocità?', options: ['count=', 'bs=', 'size=', 'chunk='], answer: 1, explanation: '`bs` (block size) detta la quantità di byte letti e scritti alla volta, ad esempio: `bs=4M`.' },
  { id: 'lpic2-206-15', topicId: 7, question: 'Quale comando genera una coppia di chiavi di autenticazione OpenSSH?', options: ['ssh-agent', 'ssh-add', 'ssh-keygen', 'ssh-copy-id'], answer: 2, explanation: '`ssh-keygen` genera matematicamente coppie di chiavi pubblica/privata per l\'autenticazione del protocollo SSH.' },

  { id: 'lpic2-207-6', topicId: 8, question: 'Cosa definisce il record Start of Authority (SOA) in un file di zona BIND?', options: ['L\'indirizzo IP del server web', 'Informazioni autorevoli sulla zona, inclusi l\'indirizzo email dell\'amministratore e i parametri di temporizzazione', 'Un elenco di tutti i sottodomini', 'Dati di geolocalizzazione per il dominio'], answer: 1, explanation: 'Il record SOA è obbligatorio in ogni zona e contiene parametri critici come il numero di serie, i tempi di refresh e il TTL negativo.' },
  { id: 'lpic2-207-7', topicId: 8, question: 'Che tipo di record DNS viene utilizzato per creare un alias da un nome a un altro nome (FQDN)?', options: ['A', 'PTR', 'CNAME', 'TXT'], answer: 2, explanation: 'Un record CNAME (Canonical Name) mappa un nome alias al vero nome canonico del dominio.' },
  { id: 'lpic2-207-8', topicId: 8, question: 'In Linux, quale utility versatile è preferita per interrogare i server DNS e debuggare i problemi di risoluzione dei nomi rispetto a `nslookup`?', options: ['dig', 'host', 'ping', 'whois'], answer: 0, explanation: '`dig` (Domain Information Groper) fornisce un output dettagliato e flessibile indispensabile per gli amministratori DNS.' },
  { id: 'lpic2-207-9', topicId: 8, question: 'Al fine di consentire la risoluzione inversa (da IP a Nome), sotto quale dominio speciale deve essere configurata la zona nel DNS?', options: ['.reverse', '.in-addr.arpa', '.ip6.arpa', 'Entrambi B e C'], answer: 3, explanation: '`in-addr.arpa` gestisce la risoluzione inversa per IPv4, mentre `ip6.arpa` è dedicato a IPv6.' },
  { id: 'lpic2-207-10', topicId: 8, question: 'Quale file di configurazione locale del sistema operativo Linux indica quali resolver (Server DNS) interrogare per primi?', options: ['/etc/hosts', '/etc/resolv.conf', '/etc/nsswitch.conf', '/etc/named.conf'], answer: 1, explanation: '`/etc/resolv.conf` elenca le direttive `nameserver` che il sistema utilizza per risolvere le query DNS.' },
  { id: 'lpic2-207-11', topicId: 8, question: 'Quale comando ricarica la configurazione del server BIND (`named`) senza terminare il processo?', options: ['named -r', 'service named restart', 'rndc reload', 'bind-init reload'], answer: 2, explanation: '`rndc` (Remote Name Daemon Control) è l\'utility di amministrazione per BIND; il sottocomando `reload` applica le modifiche alle zone in modo sicuro.' },
  { id: 'lpic2-207-12', topicId: 8, question: 'In una configurazione DNSSEC, quale record viene inserito nella zona genitore per stabilire una "catena di fiducia" verso la zona figlia?', options: ['RRSIG', 'DS (Delegation Signer)', 'DNSKEY', 'NSEC'], answer: 1, explanation: 'Il record DS contiene l\'hash della chiave DNSKEY della zona delegata e risiede nella zona del genitore.' },
  { id: 'lpic2-207-13', topicId: 8, question: 'Cos\'è TSIG nel contesto di BIND?', options: ['Un protocollo per il routing DNS', 'Una firma di transazione che utilizza chiavi segrete condivise per autenticare i trasferimenti di zona e gli aggiornamenti dinamici', 'Un tipo di record per lo streaming video', 'Un tool per comprimere i log BIND'], answer: 1, explanation: 'TSIG garantisce che le comunicazioni tra server DNS (come i trasferimenti di zona) siano autenticate tramite una chiave segreta.' },
  { id: 'lpic2-207-14', topicId: 8, question: 'Quale campo nel file di zona deve essere incrementato ogni volta che viene apportata una modifica affinché i server slave sappiano che devono aggiornarsi?', options: ['Refresh', 'Retry', 'Serial Number', 'Expire'], answer: 2, explanation: 'Il Serial Number viene confrontato dai server slave; se è superiore a quello memorizzato localmente, viene avviata una richiesta di trasferimento (AXFR/IXFR).' },
  { id: 'lpic2-207-15', topicId: 8, question: 'Per proteggere il sistema principale in caso di compromissione, in quale ambiente isolato viene spesso eseguito BIND?', options: ['Una partizione NTFS', 'Un Chroot jail', 'Una directory LDAP', 'Uno snapshot LVM'], answer: 1, explanation: 'Eseguire BIND in una "gabbia" chroot limita l\'accesso del demone solo a un sottoinsieme ristretto del filesystem.' },

  { id: 'lpic2-208-6', topicId: 9, question: 'In Apache, quale direttiva definisce la directory principale da cui vengono serviti i file del sito web?', options: ['ServerRoot', 'DocumentRoot', 'DirectoryIndex', 'PathRoot'], answer: 1, explanation: '`DocumentRoot` mappa l\'URL radice (/) a una directory fisica sul server Linux.' },
  { id: 'lpic2-208-7', topicId: 9, question: 'Per configurare Nginx come Reverse Proxy, quale direttiva viene utilizzata all\'interno di un blocco `location` per inoltrare le richieste a un server backend?', options: ['proxy_pass', 'proxy_forward', 'redirect_to', 'upstream_pass'], answer: 0, explanation: '`proxy_pass` definisce il protocollo e l\'indirizzo del server proxy verso cui inoltrare le richieste (es. http://localhost:8080).' },
  { id: 'lpic2-208-8', topicId: 9, question: 'Quale modulo Apache consente la manipolazione dinamica degli URL in ingresso tramite espressioni regolari?', options: ['mod_alias', 'mod_rewrite', 'mod_proxy', 'mod_env'], answer: 1, explanation: '`mod_rewrite` è un potente motore basato su regole che permette di riscrivere gli URL al volo per SEO o redirezioni.' },
  { id: 'lpic2-208-9', topicId: 9, question: 'Quale file può essere posizionato in una sottodirectory del sito per sovrascrivere le configurazioni globali di Apache senza riavviare il server?', options: ['.config', '.htaccess', '.apacheconf', 'index.php'], answer: 1, explanation: 'I file `.htaccess` consentono una configurazione decentralizzata per directory ma possono impattare sulle performance.' },
  { id: 'lpic2-208-10', topicId: 9, question: 'In Squid proxy, quale direttiva verrebbe utilizzata per bloccare l\'accesso a una ACL chiamata "rete_locale"?', options: ['http_access allow rete_locale', 'http_access deny rete_locale', 'acl rete_locale deny', 'block rete_locale'], answer: 1, explanation: '`http_access deny <nome_acl>` applica la regola di divieto al traffico corrispondente alla definizione dell\'ACL.' },
  { id: 'lpic2-208-11', topicId: 9, question: 'Qual è il vantaggio principale dell\'architettura a eventi di Nginx rispetto al modello basato su processi di Apache?', options: ['Supporta più linguaggi di programmazione', 'Consuma molta più RAM', 'Può gestire migliaia di connessioni simultanee con un uso minimo di risorse (RAM/CPU)', 'È più facile da configurare per i principianti'], answer: 2, explanation: 'Utilizzando un design asincrono e non bloccante, Nginx scala molto meglio sotto carichi pesanti di connessioni simultanee.' },
  { id: 'lpic2-208-12', topicId: 9, question: 'Come si definisce un server proxy "genitore" (parent) a cui Squid dovrebbe inoltrare le richieste se non può soddisfarle localmente?', options: ['cache_peer', 'proxy_parent', 'upstream_proxy', 'neighbor_server'], answer: 0, explanation: 'La direttiva `cache_peer` definisce altri server proxy e il loro ruolo (parent o sibling) nella gerarchia di caching.' },
  { id: 'lpic2-208-13', topicId: 9, question: 'In Nginx, quale parametro nel file di configurazione principale definisce quanti processi figli devono essere generati (tipicamente impostato su "auto")?', options: ['worker_connections', 'worker_processes', 'server_spawn', 'thread_pool'], answer: 1, explanation: '`worker_processes` definisce il numero di istanze di lavoro; se impostato su "auto", solitamente corrisponde al numero di core della CPU.' },
  { id: 'lpic2-208-14', topicId: 9, question: 'Quali direttive Apache vengono utilizzate all\'interno di un VirtualHost per identificare il nome del dominio primario e i suoi nomi alternativi (alias)?', options: ['ServerName / ServerAlias', 'HostName / HostAlias', 'DomainName / DomainAlias', 'VirtualName / VirtualAlias'], answer: 0, explanation: '`ServerName` definisce il dominio principale, mentre `ServerAlias` elenca altri nomi che corrispondono al medesimo VirtualHost.' },
  { id: 'lpic2-208-15', topicId: 9, question: 'Quale comando costringe Squid a rileggere i suoi file di configurazione senza arrestare il servizio?', options: ['squid reload', 'squid -k reconfigure', 'squid -s', 'service squid restart'], answer: 1, explanation: '`squid -k reconfigure` segnala al demone attivo di rianalizzare le impostazioni correnti.' },

  // --- NUOVO BATCH 3 (Argomenti 209-212) ---
  { id: 'lpic2-209-6', topicId: 10, question: 'Quale comando visualizza le connessioni attive correnti e i file bloccati su un server Samba?', options: ['smbstatus', 'testparm', 'smbclient', 'netstat -smb'], answer: 0, explanation: '`smbstatus` riporta le connessioni Samba correnti, inclusi utenti, macchine e file bloccati.' },
  { id: 'lpic2-209-7', topicId: 10, question: 'Prima di riavviare Samba, quale utility dovresti usare per controllare la correttezza interna e gli errori di sintassi di `smb.conf`?', options: ['smb-check', 'testparm', 'smbclient -t', 'smbpasswd -check'], answer: 1, explanation: '`testparm` legge `smb.conf` e lo controlla per errori di parsing della configurazione.' },
  { id: 'lpic2-209-8', topicId: 10, question: 'Quale comando consente a un utente desktop Linux di sfogliare e trasferire file in modo interattivo da una condivisione di rete Windows in modo simile all\'FTP?', options: ['mount.cifs', 'winbound', 'smbclient', 'samba-ftpd'], answer: 2, explanation: '`smbclient` è un client simile a FTP per accedere alle risorse SMB/CIFS sui server.' },
  { id: 'lpic2-209-9', topicId: 10, question: 'Quale importante differenza architettonica distingue NFSv4 da NFSv3?', options: ['NFSv4 usa solo UDP', 'NFSv4 integra il blocco dei file e il montaggio in un unico protocollo sulla porta TCP 2049, eliminando la necessità di rpcbind', 'NFSv4 non può essere montato su Internet', 'NFSv3 è più veloce per le reti geografiche (WAN)'], answer: 1, explanation: 'NFSv4 è firewall-friendly perché consolida il montaggio, il blocco e il trasferimento dei file in una singola porta (TCP 2049).' },
  { id: 'lpic2-209-10', topicId: 10, question: 'Quale comando interroga un server NFS remoto (a 192.168.1.50) per vedere quali directory sta esportando attualmente?', options: ['showmount -e 192.168.1.50', 'exportfs -v 192.168.1.50', 'nfsstat -m 192.168.1.50', 'mount -l 192.168.1.50'], answer: 0, explanation: '`showmount -e` visualizza l\'elenco delle esportazioni di un server NFS.' },
  { id: 'lpic2-209-11', topicId: 10, question: 'Cosa fornisce il comando `nfsstat`?', options: ['Riavvia il demone NFS', 'Visualizza statistiche sull\'attività del client e del server NFS per aiutare a diagnosticare problemi di prestazioni', 'Formatta un disco per NFS', 'Testa le velocità di rete tra i nodi'], answer: 1, explanation: '`nfsstat` emette statistiche dettagliate su RPC (Remote Procedure Call) e NetworkFileSystem.' },
  { id: 'lpic2-209-12', topicId: 10, question: 'In configurazioni Samba avanzate, quale daemon mappa gli identificatori SID di Windows in UID/GID Linux assegnati in un ambiente Active Directory?', options: ['smbd', 'nmbd', 'winbindd', 'kerberosd'], answer: 2, explanation: '`winbindd` risolve i nomi dai server NT e fornisce una funzione di mappatura ID unificata per gli utenti del dominio.' },
  { id: 'lpic2-209-13', topicId: 10, question: 'L\'NFS legacy (v3) si affida pesantemente a un daemon che mappa i numeri dei programmi RPC ai numeri delle porte di rete. Come si chiama questo daemon?', options: ['rpcbind (o portmap)', 'inetd', 'xinetd', 'rpc.nfsd'], answer: 0, explanation: '`rpcbind` (precedentemente `portmap`) assegna dinamicamente porte variabili per i servizi ausiliari NFS più vecchi come rpc.statd.' },
  { id: 'lpic2-209-14', topicId: 10, question: 'Quale parametro globale in `smb.conf` detta il nome del dominio Windows o del workgroup in cui apparirà il server Samba?', options: ['domain =', 'netbios name =', 'server string =', 'workgroup ='], answer: 3, explanation: 'Il parametro `workgroup` imposta il nome del workgroup/dominio.' },
  { id: 'lpic2-209-15', topicId: 10, question: 'Quale comando monta una condivisione Windows nativamente nell\'albero del filesystem Linux?', options: ['mount -t ntfs //server/share /mnt', 'mount -t smbfs //server/share /mnt', 'mount -t cifs -o username=user //server/share /mnt', 'smbclient //server/share /mnt'], answer: 2, explanation: 'Il Linux moderno utilizza il modulo kernel `cifs` (Virtual File System) per montare le condivisioni SMB.' },
  { id: 'lpic2-209-16', topicId: 10, question: 'In `/etc/exports`, cosa fa il parametro `no_root_squash`?', options: ['Impedisce completamente l\'accesso root', 'Consente all\'utente root remoto di mantenere i privilegi di root sulla directory esportata', 'Comprime i file consultati da root', 'Mappa root sull\'utente nobody'], answer: 1, explanation: 'Normalmente, NFS schiaccia (squash) le richieste root verso un UID anonimo. `no_root_squash` annulla questo comportamento, rappresentando un grave rischio per la sicurezza se usato con leggerezza.' },

  { id: 'lpic2-210-6', topicId: 11, question: 'Nella configurazione del server DHCP ISC (`dhcpd.conf`), quale parametro definisce la durata predefinita del leasing di un IP a un client se questo non richiede un intervallo specifico?', options: ['max-lease-time', 'default-lease-time', 'lease-duration', 'expire-time'], answer: 1, explanation: '`default-lease-time` è il tempo di allocazione standard in secondi.' },
  { id: 'lpic2-210-7', topicId: 11, question: 'Quale daemon ISC DHCP crea il log centralizzato degli IP in leasing, memorizzando effettivamente lo stato tra i riavvii?', options: ['/etc/dhcp/dhcpd.conf', '/var/lib/dhclient/dhclient.leases', '/var/lib/dhcp/dhcpd.leases', '/var/log/dhcpd.log'], answer: 2, explanation: 'Il file `dhcpd.leases` funge da database per tracciare le allocazioni attive.' },
  { id: 'lpic2-210-8', topicId: 11, question: 'Quali sono i quattro gruppi di gestione all\'interno di un file di configurazione del modulo PAM?', options: ['allow, deny, warn, critical', 'auth, account, password, session', 'user, group, other, root', 'login, shell, network, local'], answer: 1, explanation: 'PAM organizza le regole in auth (identità), account (validità), password (aggiornamento credenziali) e session (setup/terminazione).' },
  { id: 'lpic2-210-9', topicId: 11, question: 'In uno stack PAM, cosa succede se un modulo contrassegnato come `requisite` fallisce?', options: ['Lo stack restituisce immediatamente il fallimento senza eseguire ulteriori moduli', 'Il fallimento viene registrato, ma viene testato il modulo successivo', 'L\'utente viene reindirizzato a una shell limitata', 'All\'utente viene chiesto un CAPTCHA'], answer: 0, explanation: 'A differenza di `required`, `requisite` causa un fallimento istantaneo evitando ulteriori elaborazioni.' },
  { id: 'lpic2-210-10', topicId: 11, question: 'Per impostazione predefinita, su quale porta TCP opera l\'LDAP non crittografato?', options: ['110', '389', '636', '3306'], answer: 1, explanation: 'LDAP comunica sulla porta TCP 389, mentre LDAPS (LDAP over SSL) utilizza la porta 636.' },
  { id: 'lpic2-210-11', topicId: 11, question: 'Quale daemon è il motore principale della suite server OpenLDAP?', options: ['ldap_agent', 'named', 'slapd', 'sssd'], answer: 2, explanation: '`slapd` sta per Stand-Alone LDAP Daemon.' },
  { id: 'lpic2-210-12', topicId: 11, question: 'Quale utility a riga di comando interroga una directory LDAP utilizzando i filtri?', options: ['ldapquery', 'ldapsearch', 'ldaplookup', 'ldapfind'], answer: 1, explanation: '`ldapsearch` apre una connessione a un server LDAP, esegue il bind ed effettua una ricerca utilizzando un filtro specifico.' },
  { id: 'lpic2-210-13', topicId: 11, question: 'Quale daemon moderno viene ampiamente utilizzato in Linux per memorizzare nella cache le credenziali e gestire le connessioni a directory centralizzate come LDAP o Active Directory?', options: ['nscd', 'sssd', 'pam_unix', 'winbind'], answer: 1, explanation: 'Il System Security Services Daemon (SSSD) integra il sistema con directory centralizzate remote e fornisce il caching offline.' },
  { id: 'lpic2-210-14', topicId: 11, question: 'In OpenVPN, l\'instradamento di tutto il traffico Internet del client attraverso la VPN richiede l\'invio (push) di quale direttiva specifica al client?', options: ['push "route 0.0.0.0 0.0.0.0"', 'push "redirect-gateway def1"', 'push "default-route"', 'route-all'], answer: 1, explanation: '`redirect-gateway def1` modifica la tabella di instradamento predefinita del client per puntare al tunnel VPN.' },
  { id: 'lpic2-210-15', topicId: 11, question: 'Quale comando costringe un client Linux a rilasciare manualmente il suo indirizzo IP in leasing DHCP e ad arrestare il demone?', options: ['dhclient -x', 'dhclient -r', 'ifdown eth0', 'ip addr flush'], answer: 1, explanation: '`dhclient -r` rilascia esplicitamente il lease corrente al server e arresta il demone del client.' },
  { id: 'lpic2-210-16', topicId: 11, question: 'Qual è il suffisso/estensione standard per il file dell\'autorità di certificazione utilizzato per autenticare i client OpenVPN?', options: ['.key', '.crt', '.csr', '.ca'], answer: 1, explanation: 'I certificati (chiavi pubbliche) utilizzano generalmente l\'estensione `.crt` o `.pem`.' },

  { id: 'lpic2-211-6', topicId: 12, question: 'Quale comando visualizza il contenuto corrente della coda di posta di Postfix?', options: ['mailq', 'postqueue -p', 'Entrambi A e B', 'qstat'], answer: 2, explanation: '`mailq` è solitamente un symlink a `postqueue -p`, che stampa la coda.' },
  { id: 'lpic2-211-7', topicId: 12, question: 'Cosa fa il comando Postfix `postsuper -d ALL`?', options: ['Elimina tutti i messaggi dalla coda di posta', 'Scarica tutti i messaggi dall\'MTA', 'Distribuisce una nuova configurazione del supervisore', 'Disabilita il server di posta'], answer: 0, explanation: '`postsuper` gestisce la coda di Postfix; `-d ALL` elimina irrimediabilmente ogni messaggio in coda.' },
  { id: 'lpic2-211-8', topicId: 12, question: 'Quale parametro in `main.cf` definisce per quali nomi di dominio Postfix si considera la destinazione finale?', options: ['myhostname', 'mynetworks', 'mydestination', 'relay_domains'], answer: 2, explanation: 'Le email indirizzate ai domini elencati in `mydestination` vengono consegnate localmente.' },
  { id: 'lpic2-211-9', topicId: 12, question: 'Se vuoi che Postfix rifiuti globalmente le email provenienti da indirizzi IP di noti spammer, quale direttiva configureresti per utilizzare le DNS Blocklists (DNSBL)?', options: ['smtpd_recipient_restrictions', 'smtpd_client_restrictions', 'header_checks', 'virtual_alias_maps'], answer: 1, explanation: '`smtpd_client_restrictions = reject_rbl_client zen.spamhaus.org` valuta l\'IP connesso prima di qualsiasi transazione.' },
  { id: 'lpic2-211-10', topicId: 12, question: 'Quale porta è storicamente riservata al protocollo POP3 (non crittografato)?', options: ['25', '110', '143', '993'], answer: 1, explanation: 'Il protocollo Post Office Protocol versione 3 opera sulla porta TCP 110.' },
  { id: 'lpic2-211-11', topicId: 12, question: 'In Dovecot, qual è la porta predefinita per IMAPS (Secure IMAP su SSL/TLS)?', options: ['143', '465', '587', '993'], answer: 3, explanation: 'IMAPS sfrutta il TLS implicitamente sicuro sulla porta TCP 993.' },
  { id: 'lpic2-211-12', topicId: 12, question: 'Quale linguaggio di script MDA è considerato l\'alternativa moderna e standardizzata a Procmail, progettato specificamente per integrarsi in modo pulito con Dovecot?', options: ['Bash', 'Python', 'Sieve', 'Perl'], answer: 2, explanation: 'Sieve è un linguaggio di scripting altamente sicuro e standardizzato per filtrare le email a livello MTA/MDA.' },
  { id: 'lpic2-211-13', topicId: 12, question: 'Dove vengono tipicamente definite le ricette (recipes) di Procmail su base per utente?', options: ['/etc/procmail.conf', '~/.procmailrc', '/var/spool/mail/recipes', '~/.mailfilter'], answer: 1, explanation: 'Gli utenti creano ricette personali di instradamento della posta in `.procmailrc` nelle loro home directory.' },
  { id: 'lpic2-211-14', topicId: 12, question: 'Qual è la funzione del parametro `mynetworks` in Postfix?', options: ['Blocca lo spam da quelle reti', 'Definisce l\'elenco delle reti locali autorizzate a inoltrare la posta attraverso il server verso domini esterni', 'Mappa gli indirizzi IP locali', 'Definisce le interfacce IP su cui Postfix è in ascolto'], answer: 1, explanation: 'I client provenienti da IP che corrispondono a `mynetworks` sono implicitamente considerati affidabili per l\'inoltro (relay) della posta.' },
  { id: 'lpic2-211-15', topicId: 12, question: 'Quale comando costringe Postfix a tentare immediatamente la consegna di tutti i messaggi differiti (deferred) in attesa nella coda?', options: ['postsuper -r', 'postfix flush', 'postqueue -f', 'mailq -f'], answer: 2, explanation: '`postqueue -f` scorre la coda di posta e tenta un flush immediato.' },
  { id: 'lpic2-211-16', topicId: 12, question: 'Cosa configura la direttiva Postfix `virtual_alias_maps`?', options: ['Mappa i domini virtuali su indirizzi IP fisici', 'Inoltra le email da un indirizzo specifico (es. info@dominio.com) a caselle di posta reali', 'Mappa gli indirizzi IP esterni sui server interni', 'Crea risposte automatiche per le vacanze'], answer: 1, explanation: 'Gli alias virtuali riscrivono gli indirizzi dei destinatari, comunemente usati per l\'inoltro.' },

  { id: 'lpic2-212-6', topicId: 13, question: 'In iptables, quale switch aggiunge una regola in fondo a una catena?', options: ['-I', '-A', '-D', '-R'], answer: 1, explanation: '`-A` sta per Append, mentre `-I` inserisce una regola in cima (o a un numero di riga specificato).' },
  { id: 'lpic2-212-7', topicId: 13, question: 'Quale comando elenca tutte le regole di iptables nella tabella NAT?', options: ['iptables -L', 'iptables -t nat -L', 'iptables -nL --table nat', 'iptables --list nat'], answer: 1, explanation: '`-t nat` specifica la tabella di destinazione e `-L` elenca le regole.' },
  { id: 'lpic2-212-8', topicId: 13, question: 'Quale catena di filtraggio in iptables gestisce i pacchetti la cui destinazione finale è il server stesso?', options: ['FORWARD', 'OUTPUT', 'INPUT', 'PREROUTING'], answer: 2, explanation: 'La catena `INPUT` elabora i pacchetti in entrata indirizzati ai socket locali.' },
  { id: 'lpic2-212-9', topicId: 13, question: 'In `iptables`, cosa fa il target `MASQUERADE`?', options: ['Nasconde i dati del pacchetto', 'Traduce dinamicamente l\'IP sorgente dei pacchetti in uscita con l\'IP dell\'interfaccia di uscita', 'Blocca gli hacker noti', 'Crea un tunnel VPN'], answer: 1, explanation: 'Il mascheramento è un SNAT dinamico, ampiamente utilizzato sui router con IP pubblici dinamici.' },
  { id: 'lpic2-212-10', topicId: 13, question: 'Con Nmap, cosa specifica il flag `-sS`?', options: ['Scansione UDP', 'Scansione TCP SYN (Stealth)', 'Scansione TCP Connect', 'Scansione FIN'], answer: 1, explanation: 'La scansione SYN esegue un handshake TCP semi-aperto altamente efficiente per mappare le porte.' },
  { id: 'lpic2-212-11', topicId: 13, question: 'Quale argomento della riga di comando dice a Nmap di tentare di identificare il sistema operativo dell\'host remoto?', options: ['-O', '-sV', '-A', 'Entrambi A e C'], answer: 3, explanation: '`-O` abilita specificamente il rilevamento del sistema operativo. `-A` (Aggressive) abilita il rilevamento del sistema operativo insieme alla scansione delle versioni e degli script.' },
  { id: 'lpic2-212-12', topicId: 13, question: 'In Fail2ban, quale file dovrebbero usare gli amministratori per personalizzare le configurazioni delle jail per evitare che gli aggiornamenti dei pacchetti le sovrascrivano?', options: ['jail.conf', 'fail2ban.conf', 'jail.local', 'iptables.local'], answer: 2, explanation: '`jail.local` sovrascrive `jail.conf`, fungendo da repository sicuro per le modifiche locali.' },
  { id: 'lpic2-212-13', topicId: 13, question: 'Quale variabile in Fail2ban definisce la durata (in secondi) per cui un IP trasgressore rimane bloccato?', options: ['blocktime', 'findtime', 'maxretry', 'bantime'], answer: 3, explanation: '`bantime` definisce per quanto tempo viene lasciato in vigore l\'inserimento del DROP di iptables.' },
  { id: 'lpic2-212-14', topicId: 13, question: 'Qual è il framework del kernel fondamentale su cui si basa iptables per agganciarsi allo stack di rete?', options: ['BPF', 'Netfilter', 'TCP Wrapper', 'AppArmor'], answer: 1, explanation: 'Netfilter fornisce gli "hook" nel kernel Linux che consentono a iptables/nftables di intercettare e manipolare i pacchetti.' },
  { id: 'lpic2-212-15', topicId: 13, question: 'Quale comando salva in modo permanente le regole di iptables nello standard output per la creazione di script di backup nella maggior parte delle distribuzioni?', options: ['iptables-save', 'iptables-backup', 'iptables -S', 'service iptables save'], answer: 0, explanation: '`iptables-save` scarica le regole in un formato leggibile dalla macchina (che può essere ripristinato tramite `iptables-restore`).' },
  { id: 'lpic2-212-16', topicId: 13, question: 'Cos\'è un Network Vulnerability Test (NVT) nel contesto di OpenVAS/Greenbone?', options: ['Uno sniffer di pacchetti', 'Uno script plugin che fornisce la logica per rilevare una specifica vulnerabilità su un host remoto', 'Una tecnica di scansione delle porte', 'Una regola di rilevamento delle intrusioni'], answer: 1, explanation: 'Gli NVT sono essenzialmente gli script di firma eseguiti da OpenVAS per confermare se un bersaglio è vulnerabile.' },
  { id: 'lpic2-212-17', topicId: 13, question: 'Quale comando svuota (cancella) tutte le regole nella tabella iptables attualmente selezionata?', options: ['iptables -X', 'iptables -Z', 'iptables -F', 'iptables -R'], answer: 2, explanation: '`-F` (Flush) cancella istantaneamente tutte le regole da tutte le catene (o da una catena specificata).' },
];
